import React, { useEffect, useState } from 'react';
import { Table, Button, Popconfirm, Modal, message, Avatar, Space, Layout, Menu, Form, Input, Row, Col, Typography, Tooltip, Dropdown } from 'antd';
import { EditOutlined, DeleteOutlined, EyeOutlined, QrcodeOutlined, DownloadOutlined, MoreOutlined, UserOutlined } from '@ant-design/icons';
import { logout } from '../utils/auth';
import { useNavigate } from 'react-router-dom';
import { uploadToCloudinary } from '../utils/cloudinary';

const { Sider, Content, Header } = Layout;
const { Title, Text } = Typography;

export default function ViewAllUsers() {
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(false);
  const [editingUser, setEditingUser] = useState(null);
  const [editModalVisible, setEditModalVisible] = useState(false);
  const [editForm] = Form.useForm();
  const [editLoading, setEditLoading] = useState(false);

  const email = localStorage.getItem('adminEmail') || 'Super Admin';
  const navigate = useNavigate();
  const [editProfilePic, setEditProfilePic] = useState(null);
  const [editPreview, setEditPreview] = useState('');

  const fetchUsers = async () => {
    setLoading(true);
    try {
      const token = localStorage.getItem('token');
      const res = await fetch(`${process.env.REACT_APP_API_URL || ''}/api/users`, {
        headers: { 'Authorization': `Bearer ${token}` },
      });
      const data = await res.json();
      if (res.ok) setUsers(data);
      else message.error(data.message || 'Failed to fetch users');
    } catch (err) {
      message.error('Failed to fetch users');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchUsers(); }, []);

  const handleDelete = async (id) => {
    const token = localStorage.getItem('token');
    try {
      const res = await fetch(`${process.env.REACT_APP_API_URL || ''}/api/users/${id}`, {
        method: 'DELETE',
        headers: { 'Authorization': `Bearer ${token}` },
      });
      const data = await res.json();
      if (res.ok) {
        message.success('User deleted');
        setUsers(users.filter(u => u._id !== id));
      } else {
        message.error(data.message || 'Failed to delete user');
      }
    } catch (err) {
      message.error('Failed to delete user');
    }
  };

  const handleEdit = (user) => {
    setEditingUser(user);
    setEditModalVisible(true);
    setEditProfilePic(null);
    setEditPreview(user.profilePic || '');
    editForm.setFieldsValue({
      name: user.name || '',
      email: user.email || '',
      phoneNumber: user.phoneNumber || '',
      nic: user.nic || '',
      school: user.school || '',
      age: user.age || ''
    });
  };

  const handleEditModalClose = () => {
    setEditModalVisible(false);
    editForm.resetFields();
    setEditProfilePic(null);
    setEditPreview('');
    setEditLoading(false);
  };

  const handleEditFileChange = e => {
    const file = e.target.files[0];
    setEditProfilePic(file || null);
    setEditPreview(file ? URL.createObjectURL(file) : (editingUser?.profilePic || ''));
  };

  const handleEditSubmit = async () => {
    try {
      setEditLoading(true);
      const values = await editForm.validateFields();
      let profilePicUrl = editingUser.profilePic;

      if (editProfilePic) {
        try {
          profilePicUrl = await uploadToCloudinary(editProfilePic);
        } catch (uploadError) {
          message.error('Failed to upload profile picture');
          setEditLoading(false);
          return;
        }
      }

      const token = localStorage.getItem('token');
      const res = await fetch(`${process.env.REACT_APP_API_URL || ''}/api/users/${editingUser._id}`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`,
        },
        body: JSON.stringify({ ...values, profilePic: profilePicUrl }),
      });

      const data = await res.json();
      if (res.ok) {
        message.success('User updated successfully');
        setEditModalVisible(false);
        setTimeout(fetchUsers, 500);
      } else {
        message.error(data.message || 'Failed to update user');
      }
    } catch (err) {
      if (err.errorFields) {
        message.error('Please check the form fields');
      } else {
        message.error('Failed to update user');
      }
    } finally {
      setEditLoading(false);
    }
  };

  const handleResendQR = async (userId, userName) => {
    try {
      const token = localStorage.getItem('token');
      const res = await fetch(`${process.env.REACT_APP_API_URL || ''}/api/users/${userId}/resend-qr`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`,
        },
      });
      const data = await res.json();
      if (res.ok) {
        message.success(`QR code sent to ${userName}'s email successfully!`);
      } else {
        message.error(data.message || 'Failed to send QR code');
      }
    } catch (err) {
      message.error('Failed to send QR code');
    }
  };

  // Enhanced mobile responsive columns
  const columns = [
    { 
      title: 'ID', 
      dataIndex: '_id', 
      key: '_id',
      responsive: ['lg'],
      render: (id) => <Text code style={{ fontSize: 11 }}>{id}</Text>
    },
    { 
      title: 'Name', 
      dataIndex: 'name', 
      key: 'name',
      responsive: ['lg'],
      render: (name) => <Text strong>{name}</Text>
    },
    { 
      title: 'Email', 
      dataIndex: 'email', 
      key: 'email',
      responsive: ['lg'],
      render: (email) => <Text>{email}</Text>
    },
    { 
      title: 'Phone', 
      dataIndex: 'phoneNumber', 
      key: 'phoneNumber',
      responsive: ['lg'],
      render: (phone) => <Text>{phone}</Text>
    },
    { 
      title: 'NIC', 
      dataIndex: 'nic', 
      key: 'nic',
      responsive: ['lg'],
      render: (nic) => <Text code>{nic}</Text>
    },
    { 
      title: 'School',
      dataIndex: 'school',
      key: 'school',
      responsive: ['lg'],
      render: (school) => <Text>{school}</Text>
    },
    {
      title: 'Age',
      dataIndex: 'age',
      key: 'age',
      responsive: ['lg'],
      render: (age) => <Text>{age}</Text>
    },
    { 
      title: 'Profile', 
      dataIndex: 'profilePic', 
      key: 'profilePic',
      responsive: ['lg'],
      render: url => url ? <Avatar src={url} size={32} /> : <Avatar icon={<UserOutlined />} size={32} />
    },
    {
      title: 'Actions',
      key: 'actions',
      fixed: 'right',
      width: 120,
      render: (_, user) => {
        const actionItems = [
          {
            key: 'view',
            label: 'View Profile',
            icon: <EyeOutlined />, 
            onClick: () => window.open(`${process.env.REACT_APP_API_URL || ''}/user/${user._id}`, '_blank')
          },
          {
            key: 'edit',
            label: 'Edit User',
            icon: <EditOutlined />, 
            onClick: () => handleEdit(user)
          },
          {
            key: 'resend',
            label: 'Resend QR Code',
            icon: <QrcodeOutlined />, 
            onClick: () => handleResendQR(user._id, user.name)
          },
          {
            key: 'delete',
            label: 'Delete User',
            icon: <DeleteOutlined />, 
            danger: true,
            onClick: () => handleDelete(user._id)
          }
        ];

        return (
          <Space wrap>
            {/* Desktop buttons */}
            <div style={{ display: { xs: 'none', md: 'flex' }, gap: 4 }}>
              <Tooltip title="View Profile">
                <Button 
                  icon={<EyeOutlined />} 
                  size="small"
                  onClick={() => window.open(`${process.env.REACT_APP_API_URL || ''}/user/${user._id}`, '_blank')}
                />
              </Tooltip>
              <Tooltip title="Edit User">
                <Button 
                  icon={<EditOutlined />} 
                  size="small"
                  onClick={() => handleEdit(user)}
                />
              </Tooltip>
              <Tooltip title="Resend QR Code">
                <Button 
                  icon={<QrcodeOutlined />} 
                  size="small"
                  onClick={() => handleResendQR(user._id, user.name)}
                />
              </Tooltip>
              <Popconfirm 
                title="Delete user?" 
                description="This action cannot be undone."
                onConfirm={() => handleDelete(user._id)} 
                okText="Yes" 
                cancelText="No"
                okType="danger"
              >
                <Button icon={<DeleteOutlined />} danger size="small" />
              </Popconfirm>
            </div>
            {/* Mobile dropdown */}
            <div style={{ display: { xs: 'block', md: 'none' } }}>
              <Dropdown
                menu={{ items: actionItems }}
                trigger={['click']}
                placement="bottomRight"
              >
                <Button icon={<MoreOutlined />} size="small" />
              </Dropdown>
            </div>
          </Space>
        );
      },
    },
  ];

  return (
    <Layout className="min-h-screen bg-primary-50">
      <Sider breakpoint="lg" collapsedWidth="0" className="bg-primary-900">
        <img
          src={process.env.PUBLIC_URL + '/IMG-20230930-WA0000-removebg-preview.png'}
          alt="Scout Logo"
          className="w-24 h-24 object-contain mx-auto my-6 rounded-full border-4 border-primary-200 shadow-md"
        />
        <Menu
          theme="dark"
          mode="inline"
          defaultSelectedKeys={['view-all-users']}
          onClick={({ key }) => {
            if (key === 'overview') navigate('/dashboard/super');
            if (key === 'add') navigate('/dashboard/super/add-user');
            if (key === 'view-all-users') navigate('/dashboard/super/view-all-users');
            if (key === 'update-duty') navigate('/dashboard/super/update-duty');
            if (key === 'attendance-history') navigate('/dashboard/super/attendance-history');
          }}
          items={[
            { key: 'overview', label: 'Overview' },
            { key: 'add', label: 'Add New User' },
            { key: 'view-all-users', label: 'View All Users' },
            { key: 'update-duty', label: 'Update Duty Times' },
            { key: 'attendance-history', label: 'Attendance History' },
          ]}
          className="bg-primary-900 text-white"
        />
      </Sider>
      <Layout>
        <Header className="bg-white flex justify-between items-center px-6 shadow-soft">
          <div>
            <b className="text-primary-700">{email}</b> <span className="ml-2 px-2 py-1 text-xs font-medium bg-primary-500 text-white rounded-full">super</span>
          </div>
          <Button type="primary" danger className="bg-red-600 hover:bg-red-700" onClick={logout}>Logout</Button>
        </Header>
        <Content className="m-6 bg-white rounded-2xl shadow-soft p-6">
          <Row justify="space-between" align="middle" className="mb-6">
            <Col>
              <Title level={3} className="!text-primary-700 !mb-0">All Users</Title>
            </Col>
            <Col>
              <Button 
                type="primary" 
                icon={<DownloadOutlined />}
                className="bg-primary-500 hover:bg-primary-600 border-none"
                onClick={() => {
                  const csvContent = [
                    ['User ID', 'Name', 'Email', 'Phone Number', 'NIC', 'Profile Picture URL'],
                    ...users.map(user => [
                      user._id,
                      user.name || '',
                      user.email || '',
                      user.phoneNumber || '',
                      user.nic || '',
                      user.profilePic || ''
                    ])
                  ].map(row => row.join(',')).join('\n');

                  const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
                  const link = document.createElement('a');
                  const url = URL.createObjectURL(blob);
                  link.setAttribute('href', url);
                  link.setAttribute('download', `all_users_${new Date().toISOString().split('T')[0]}.csv`);
                  link.style.visibility = 'hidden';
                  document.body.appendChild(link);
                  link.click();
                  document.body.removeChild(link);
                }}
              >
                Export to CSV
              </Button>
            </Col>
          </Row>
          <div className="overflow-x-auto rounded-xl shadow-soft">
            <Table 
              columns={columns} 
              dataSource={users} 
              rowKey="_id" 
              loading={loading}
              scroll={{ x: 1200 }}
              pagination={{
                showSizeChanger: true,
                showQuickJumper: true,
                showTotal: (total, range) => `${range[0]}-${range[1]} of ${total} users`,
                pageSizeOptions: ['10', '20', '50', '100'],
                responsive: true
              }}
              size="middle"
            />
          </div>
          <Modal
            title={<span className="text-primary-700">Edit User</span>}
            open={editModalVisible}
            onCancel={handleEditModalClose}
            onOk={handleEditSubmit}
            okText="Save"
            cancelText="Cancel"
            confirmLoading={editLoading}
            width={600}
            destroyOnClose
            className="rounded-2xl"
          >
            <Form
              form={editForm}
              layout="vertical"
              autoComplete="off"
            >
              <Row gutter={16}>
                <Col xs={24} md={12}>
                  <Form.Item
                    label="Name"
                    name="name"
                    rules={[{ required: true, message: 'Please enter name' }]}
                  >
                    <Input placeholder="Enter name" />
                  </Form.Item>
                </Col>
                <Col xs={24} md={12}>
                  <Form.Item
                    label="Email"
                    name="email"
                    rules={[
                      { required: true, message: 'Please enter email' },
                      { type: 'email', message: 'Please enter a valid email' }
                    ]}
                  >
                    <Input placeholder="Enter email" />
                  </Form.Item>
                </Col>
              </Row>

              <Row gutter={16}>
                <Col xs={24} md={12}>
                  <Form.Item
                    label="Phone Number"
                    name="phoneNumber"
                    rules={[{ required: true, message: 'Please enter phone number' }]}
                  >
                    <Input placeholder="Enter phone number" />
                  </Form.Item>
                </Col>
                <Col xs={24} md={12}>
                  <Form.Item
                    label="NIC"
                    name="nic"
                    rules={[{ required: true, message: 'Please enter NIC' }]}
                  >
                    <Input placeholder="Enter NIC" />
                  </Form.Item>
                </Col>
              </Row>

              <Row gutter={16}>
                <Col xs={24} md={12}>
                  <Form.Item
                    label="School"
                    name="school"
                    rules={[{ required: false }]}
                  >
                    <Input placeholder="Enter school" />
                  </Form.Item>
                </Col>
                <Col xs={24} md={12}>
                  <Form.Item
                    label="Age"
                    name="age"
                    rules={[{ required: false, type: 'number', min: 1, max: 120, message: 'Please enter a valid age' }]}
                  >
                    <Input type="number" placeholder="Enter age" />
                  </Form.Item>
                </Col>
              </Row>

              <Form.Item label="Profile Photo">
                <div style={{ display: 'flex', alignItems: 'center', gap: 16, flexWrap: 'wrap' }}>
                  <input 
                    type="file" 
                    accept="image/*" 
                    onChange={handleEditFileChange}
                    style={{ flex: 1, minWidth: 200 }}
                  />
                  {editPreview && (
                    <Avatar src={editPreview} size={64} icon={<UserOutlined />} />
                  )}
                </div>
                <Text type="secondary" style={{ fontSize: 12 }}>
                  Leave empty to keep current profile picture
                </Text>
              </Form.Item>
            </Form>
          </Modal>
        </Content>
      </Layout>
    </Layout>
  );
}
